    "entityType": "source-control",
    "schemaVersion": "1.4.0",
    "title": "Control: ism-1555",
    "sourceProduct": "core",
    "recordStatus": "active",
    "controlId": "ism-1555",
    "statement": "Before travelling overseas with mobile devices, personnel take the following actions: - record all details of the mobile devices being taken, such as product types, serial numbers and International Mobile Equipment Identity numbers - update all operating systems and applications - remove all non-essential data, applications and user accounts - backup all remaining data, applications and settings.",
    "profileTags": [
      "master-catalog"
    ],
